        {/* Global Error Alert */}
        {globalError && (
          <div className="absolute top-20 left-1/2 -translate-x-1/2 z-50 bg-red-50 border border-red-200 text-red-700 px-6 py-4 rounded-lg flex items-center gap-3 shadow-lg">
            <AlertCircle size={20} />
            <p>{globalError}</p>
            <button 
              onClick={() => setGlobalError(null)} 
              className="ml-4 text-sm font-bold hover:underline"
            >
              Fechar
            </button>
          </div>
        )}

        {/* Empty State / Upload View */}
        {!hasItems && (
          <div className="w-full h-full flex flex-col items-center justify-center p-4 overflow-y-auto">
            <div className="max-w-3xl w-full animate-in fade-in zoom-in duration-500">
              <div className="text-center mb-10">
                <h2 className="text-3xl md:text-4xl font-bold text-slate-900 mb-4 tracking-tight">
                  Transforme Vídeos em Texto
                </h2>
                <p className="text-lg text-slate-600 max-w-2xl mx-auto">
