                ].map((item, idx) => (
                  <div key={idx} className="bg-white p-5 rounded-xl shadow-sm border border-slate-100 hover:shadow-md transition-shadow">
                    <div className="font-bold text-slate-800 text-lg mb-1">{item.label}</div>
