                              if (msg.trim().startsWith('{')) {
                                try {
                                    const parsed = JSON.parse(msg);
                                    if (parsed.error?.message) msg = parsed.error.message;
                                } catch (e) {}
                              }

                              if (msg.includes('429') || msg.includes('Resource has been exhausted') || msg.includes('quota')) {
                                return "Limite de cota da API excedido (429). O sistema tentará novamente em breve.";
                              }

                              return msg;
                           })()}
                         </p>
                         <button 
                            onClick={() => retryItem(selectedItem.id)}
                            className="flex items-center gap-2 px-5 py-2.5 bg-indigo-600 text-white rounded-lg font-medium hover:bg-indigo-700 transition-colors shadow-sm"
