                                : selectedItem.status === 'PENDING' 
                                    ? "Aguardando na fila..." 
                                    : "IA analisando e transcrevendo..."
                            }
                            progress={selectedItem.progress || 0}
                         />
                         {isPaused && (
                            <p className="mt-4 text-xs text-amber-600 bg-amber-50 px-3 py-1 rounded-full animate-pulse">
